          "label": "B",
          "text": "20"
        },
        {
          "label": "C",
          "text": "30"
        },
        {
          "label": "D",
          "text": "60"
        }
      ],
      "answer": "C",
      "solution_text": "$\\frac{A_6^6}{A_4^4} = 30$",
